const IES_ADOLESCENT = 'https://ies.ed.gov/ncee/WWC/PracticeGuide/8/Published';
const IDA_KPS = 'https://dyslexiaida.org/knowledge-and-practices/';
const NCII_PM = 'https://intensiveintervention.org/data-based-individualization/progress-monitoring';
const NCII_TOOLS = 'https://intensiveintervention.org/tools-charts/overview';
const WIDA = 'https://wida.wisc.edu/news/wida-unveils-new-edition-english-language-development-standards-framework';
const FERPA = 'https://studentprivacy.ed.gov/ferpa';
const IDEA_EVAL = 'https://sites.ed.gov/idea/regs/b/d/300.304';
const q = (promptA, promptB, correct, distractors, rationale, difficulty = 'application') => ({ promptA, promptB, correct, distractors, rationale, difficulty });

module.exports = [
  {
    id: 'literacy-foundations-development-profiles', chapterId: 'read5302-ch-01', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Literacy Foundations, Development, and Learner Profiles', references: [ETS, ILA, ILA_MATRIX, IDA_KPS],
    questions: [
      q('How should a reading specialist use a developmental literacy continuum?', 'A team asks whether literacy skills always emerge in a rigid sequence. What is the best response?', 'Use the continuum to anticipate relationships and prerequisites while assessing the individual learner rather than treating stages as fixed gates.', ['Require every learner to master skills at the same age.', 'Skip foundational evidence when comprehension is weak.', 'Use grade placement as the only indicator of instructional need.'], 'Literacy components develop in related and partly overlapping ways; a continuum organizes assessment and instruction but does not erase individual, linguistic, cultural, disability, or opportunity differences.'),
      q('Which relationship is central to reading comprehension?', 'A student understands spoken explanations but cannot identify many printed words. What should the specialist investigate?', 'Reading comprehension depends on both efficient word recognition and language comprehension, so each component should be assessed.', ['Comprehension depends only on reading rate.', 'Listening comprehension makes decoding unnecessary.', 'Word recognition alone guarantees text understanding.'], 'Word recognition and language comprehension make distinct, interacting contributions; instructional planning should locate the learner’s relative strengths and needs rather than infer one from the other.'),
      q('What is the instructional value of oral-language assessment?', 'Why should vocabulary, syntax, narrative, and listening comprehension be considered in a literacy evaluation?', 'Oral-language evidence helps explain comprehension and expression and guides language-rich reading and writing instruction.', ['It replaces direct assessment of print skills.', 'It establishes intelligence from conversation.', 'It is relevant only before kindergarten.'], 'Oral language supports vocabulary, syntax, discourse, inference, comprehension, and written expression across grades, but it must be integrated with direct print and writing evidence.'),
      q('How should a specialist interpret a diverse literacy profile?', 'Two students have the same comprehension score but different decoding and language patterns. What follows?', 'Analyze component skills and contexts separately because the same overall score can reflect different instructional needs.', ['Assign identical intervention from the total score.', 'Assume both students have dyslexia.', 'Select the lowest-grade workbook for both students.'], 'Composite performance can conceal different mechanisms; disaggregating word recognition, language, fluency, knowledge, writing, opportunity, and task conditions supports more precise instruction.'),
      q('Which pattern is commonly associated with dyslexia?', 'A learner has persistent difficulty reading unfamiliar words accurately and spelling despite appropriate instruction. What should the team consider?', 'A word-level reading difficulty involving accurate or fluent recognition, decoding, and spelling, evaluated comprehensively and under current criteria.', ['A disorder defined by reversing letters.', 'Low motivation as the necessary cause.', 'A comprehension problem that never affects word reading.'], 'Dyslexia is not established by reversals or a single score; evaluation considers persistent word-level patterns, instruction, language, development, functional impact, and exclusionary and co-occurring factors.'),
      q('How should attention, memory, and processing speed be used in literacy planning?', 'A teacher attributes every reading error to slow processing. What should the specialist do?', 'Consider cognitive and behavioral factors as part of the learning context while directly assessing the literacy skills and instructional response.', ['Treat processing speed as a complete reading diagnosis.', 'Ignore observable word-reading errors.', 'Delay literacy intervention until cognition changes.'], 'Attention, verbal memory, automaticity, processing speed, and graphomotor control can affect performance, but direct literacy evidence remains necessary for instructional and differential decisions.'),
      q('What makes a literacy curriculum coherent?', 'A school uses unrelated activities across grades without a shared progression. What should the specialist recommend?', 'Align standards, evidence-based skill progressions, texts, writing, assessment, intervention, and professional learning across grades.', ['Adopt more isolated worksheets without review.', 'Use one commercial lesson identically for every learner.', 'Let each assessment define a separate curriculum.'], 'Coherence connects goals, content, instructional routines, assessment, intervention, materials, and grade-to-grade development while allowing responsive adaptation.'),
      q('How should culture and language influence literacy instruction?', 'A multilingual learner uses knowledge from a home language while reading English. What is the best interpretation?', 'Treat linguistic and cultural knowledge as resources while explicitly teaching new English forms and monitoring access and growth.', ['Require the learner to suppress the home language.', 'Interpret every cross-language feature as disability.', 'Avoid culturally familiar texts because they reduce rigor.'], 'Asset-based instruction connects prior knowledge and cross-linguistic resources with explicit teaching of English language and literacy, without confusing difference, opportunity, and disability.'),
    ],
  },
  {
    id: 'phonological-awareness-print-alphabetic', chapterId: 'read5302-ch-02', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Phonological Awareness, Print Concepts, and the Alphabetic Principle', references: [ETS, IES_FOUNDATIONS, IDA_KPS, ILA_MATRIX],
    questions: [
      q('How do phonological awareness and phonemic awareness differ?', 'A teacher asks whether syllable blending and phoneme deletion measure the same level of sound awareness. What is correct?', 'Phonological awareness covers spoken sound structures broadly; phonemic awareness focuses specifically on individual phonemes.', ['Both require printed letters.', 'Phonics is the broader oral category.', 'Phonemic awareness concerns word meanings.'], 'Phonological awareness includes words, syllables, onset-rime, and phonemes; phonemic awareness is the most specific level and can be practiced orally before or alongside graphemes.'),
      q('Which task measures phoneme segmentation?', 'A student is asked to say every sound in “ship.” Which skill is being assessed?', 'Separating a spoken word into its individual phonemes.', ['Combining phonemes to form a word.', 'Naming the letters in a word.', 'Identifying the meaning of a morpheme.'], 'Segmentation requires identifying the sequence of phonemes in a spoken word; the number of sounds need not equal the number of printed letters.'),
      q('Which task measures phoneme manipulation?', 'A learner changes the first sound in “map” to /s/ and says “sap.” What skill is demonstrated?', 'Phoneme substitution, a form of phoneme manipulation.', ['Print-directionality knowledge.', 'Syllable counting only.', 'Vocabulary categorization.'], 'Deleting, adding, or substituting phonemes requires deliberate manipulation of the sound sequence and is more complex than recognition alone.'),
      q('What is the alphabetic principle?', 'What understanding allows a beginning reader to connect spoken words with printed words?', 'Letters and letter patterns represent the phonemes in spoken language in systematic ways.', ['Every letter always represents one sound.', 'Word meaning can be derived from letter shape alone.', 'Print is memorized only as whole visual pictures.'], 'The alphabetic principle links phonology and orthography; English correspondences vary, so teaching progresses from common transparent patterns to more complex ones.'),
      q('Which activity addresses concepts of print?', 'A child points to the first word, tracks left to right, and distinguishes a letter from a word. What is being developed?', 'Understanding how print is organized and functions in books and written language.', ['Advanced morphological analysis.', 'Silent-reading rate.', 'Norm-referenced interpretation.'], 'Concepts of print include directionality, word boundaries, book handling, and distinctions among letters, words, and sentences that support access to alphabetic instruction.'),
      q('Why can phonemic-awareness instruction include letters?', 'A specialist adds grapheme tiles after students can blend sounds orally. What is the rationale?', 'Connecting phonemes with graphemes can strengthen transfer from oral awareness to decoding and spelling.', ['Letters convert the activity into vocabulary instruction only.', 'Oral sound awareness must end before print is introduced.', 'The tiles eliminate the need for explicit feedback.'], 'Sound awareness and letter–sound knowledge are mutually supportive; carefully linking them helps students apply phonemic skills to reading and encoding.'),
      q('What is a useful sequence for phonological-awareness instruction?', 'Students can recognize rhyme but cannot blend or segment phonemes. What next step is most defensible?', 'Use explicit modeling and supported practice that moves from accessible larger units toward blending, segmenting, and manipulating phonemes based on data.', ['Begin with advanced Latin roots.', 'Require independent silent reading only.', 'Repeat rhyme identification indefinitely without monitoring.'], 'Instruction should be explicit, cumulative, responsive, and focused on the skills needed for word reading rather than tied mechanically to one universal sequence.'),
      q('A student confuses phonological awareness with phonics. Which clarification is best?', 'A coach observes a lesson asking students to name printed letter–sound correspondences but calls it phonemic awareness. How should the coach respond?', 'Phonological and phonemic awareness concern spoken sound structures; phonics explicitly connects those sounds with print.', ['Phonics concerns comprehension strategies.', 'Phonemic awareness always uses written words.', 'The terms are interchangeable in every context.'], 'Clear construct labels help teams select aligned assessments and instruction: oral sound analysis is distinct from, though closely related to, print–sound mapping.'),
    ],
  },
  {
    id: 'phonics-word-recognition-spelling-morphology', chapterId: 'read5302-ch-03', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Phonics, Word Recognition, Spelling, and Morphology', references: [ETS, IES_FOUNDATIONS, IDA_KPS, ILA_MATRIX],
    questions: [
      q('What is the best initial approach to teaching a new phonics pattern?', 'Students are learning a common vowel correspondence. Which lesson design is strongest?', 'Explicitly model the sound–spelling relationship, guide blending and encoding, and apply it in controlled words and connected text.', ['Ask students to infer the pattern from an unrelated story without guidance.', 'Have students memorize definitions only.', 'Teach several conflicting exceptions before the common pattern.'], 'Explicit explanation, cumulative practice, corrective feedback, spelling, and connected-text application help students establish and generalize a new correspondence.'),
      q('Why use decodable text during early phonics application?', 'What is the main purpose of a passage closely aligned with recently taught correspondences?', 'It gives students a high opportunity to practice applying taught decoding patterns in connected reading.', ['It permanently limits students to one text type.', 'It measures listening comprehension without print.', 'It replaces language-rich read-alouds and knowledge building.'], 'Aligned decodable text supports transfer and accuracy while a complete literacy program also includes rich oral language, diverse texts, vocabulary, knowledge, and writing.'),
      q('How should irregular high-frequency words be taught?', 'A frequently encountered word contains both regular and unexpected spellings. What should the teacher emphasize?', 'Map the regular phoneme–grapheme parts explicitly and identify the unexpected part while connecting pronunciation and meaning.', ['Treat every letter as arbitrary.', 'Require visual memorization without sound analysis.', 'Avoid the word until every exception is taught.'], 'Analyzing what is regular and what is unusual supports orthographic learning more precisely than presenting the entire word as a visual shape.'),
      q('What supports accurate multisyllabic word reading?', 'An adolescent can read short words but guesses at long academic words. What should intervention include?', 'Cumulative instruction in syllable patterns, vowel and consonant correspondences, morphology, flexible division, and meaning checks.', ['Counting letters and choosing the shortest pronunciation.', 'Using context to replace word analysis.', 'Memorizing one pronunciation for every prefix.'], 'Multisyllabic decoding integrates orthographic chunks, syllable and morpheme knowledge, pronunciation flexibility, vocabulary, and confirmation in context.'),
      q('Why teach morphology?', 'How can roots, bases, prefixes, and suffixes support older readers?', 'Morpheme analysis supports decoding, spelling, vocabulary, and meaning across related words.', ['It is useful only for grammar labels.', 'It eliminates the need for phonics.', 'It applies only to words of Anglo-Saxon origin.'], 'Morphology links word form and meaning and becomes increasingly valuable in academic language while working alongside phonological, orthographic, and contextual knowledge.'),
      q('What is orthographic mapping?', 'How do readers establish rapid access to a word after successful encounters?', 'They bond a word’s phonemes, graphemes, and meaning in memory through accurate analysis and repeated successful retrieval.', ['They store the outline of the word as a picture.', 'They memorize the page location.', 'They infer the word from context without attending to letters.'], 'Orthographic mapping depends on phonemic proficiency and knowledge of spelling patterns; it explains why accurate decoding supports increasingly automatic word recognition.'),
      q('How does spelling instruction support reading?', 'Why should encoding be included in a decoding intervention?', 'Spelling requires analysis of phoneme–grapheme and morphological structure, reinforcing the representations used in word reading.', ['Spelling and reading use unrelated systems.', 'Encoding should wait until reading is fluent.', 'Copying word lists provides the same evidence as generative spelling.'], 'Reading and spelling are reciprocal: generative encoding exposes what a learner understands about sounds, patterns, syllables, and morphemes and strengthens those links.'),
      q('Which error analysis best guides phonics instruction?', 'A student repeatedly reads “plan” as “pan” and spells “best” as “bet.” What should the specialist examine?', 'Whether the student represents and blends consonant clusters accurately in both decoding and encoding.', ['Whether the student knows the story theme.', 'Whether the font is the preferred color.', 'Whether the student can define every word.'], 'Parallel omissions in reading and spelling suggest a specific cluster or phoneme-sequence need that can be confirmed and addressed explicitly.'),
      q('What is the best response when context and decoding conflict?', 'A student reads a word that fits the sentence meaning but does not match the printed letters. What should the teacher prompt?', 'Return to the graphemes, blend or analyze the word accurately, then confirm that the pronunciation and meaning fit the sentence.', ['Accept the substitution because the meaning is plausible.', 'Cover the word and guess again.', 'Ignore print and reread only for expression.'], 'Context confirms meaning and pronunciation but should not replace close attention to the orthographic information needed for accurate word recognition.'),
    ],
  },
  {
    id: 'fluency-vocabulary-comprehension-knowledge', chapterId: 'read5302-ch-04', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Fluency, Vocabulary, Comprehension, and Knowledge Building', references: [ETS, IES_FOUNDATIONS, IES_ADOLESCENT, ILA_MATRIX],
    questions: [
      q('What are the central dimensions of oral-reading fluency?', 'A team reports words correct per minute but ignores expression and errors. What is missing?', 'Accuracy, appropriate rate or automaticity, and prosody, interpreted with text difficulty and comprehension.', ['Vocabulary breadth alone.', 'Silent-reading preference only.', 'Handwriting speed and spelling.'], 'Fluency coordinates accurate, increasingly automatic word reading with phrasing and expression; rate without accuracy, meaning, text context, or prosody is incomplete.'),
      q('Which practice is most likely to improve fluency?', 'A student reads accurately but slowly and without phrasing. Which support is appropriate?', 'Use modeled and repeated oral reading of suitable text with specific feedback, phrasing support, and comprehension checks.', ['Require faster independent reading without feedback.', 'Move immediately to much harder text.', 'Replace connected reading with word definitions only.'], 'Purposeful repeated reading and guided oral practice can build automaticity and prosody when the text is accessible and feedback preserves accuracy and meaning.'),
      q('What makes vocabulary instruction robust?', 'A specialist plans instruction for high-utility academic words in a science unit. What should it include?', 'Student-friendly explanations, morphology and semantic relationships, varied meaningful contexts, active use, and cumulative review.', ['One dictionary-copying exercise.', 'A single pretest followed by no instruction.', 'Teaching every unknown word with equal intensity.'], 'Vocabulary grows through explicit instruction, word analysis, rich language and reading, multiple exposures, retrieval, and application across speaking, reading, and writing.'),
      q('How should context be used to infer word meaning?', 'A sentence provides a possible meaning for an unfamiliar word. What should a reader do next?', 'Form a tentative meaning, analyze word parts when useful, and verify it against the broader text and a reliable source when needed.', ['Assume the nearest word is always a synonym.', 'Ignore morphology and syntax.', 'Treat the first guess as final.'], 'Context clues vary in quality; strategic readers combine syntax, discourse, morphology, knowledge, and verification rather than relying on an isolated cue.'),
      q('What is effective comprehension-strategy instruction?', 'Students can name “summarize” but do not use it while reading. What should the teacher add?', 'Explain and model the strategy, guide practice in authentic texts, prompt metacognitive monitoring, and gradually release responsibility.', ['Assign more summaries without modeling.', 'Teach a mnemonic as the final outcome.', 'Use only texts students already memorized.'], 'Strategies are purposeful routines for constructing and monitoring meaning; instruction should make decisions visible and then support flexible independent use.'),
      q('Why does knowledge building matter for comprehension?', 'Two equally accurate decoders differ in understanding a history passage. What may explain the difference?', 'Relevant vocabulary, background and domain knowledge, language comprehension, and inferential connections influence text understanding.', ['Decoding accuracy guarantees identical comprehension.', 'Prior knowledge should never be activated.', 'Comprehension is determined only by passage length.'], 'Readers integrate text information with language and knowledge; coherent text sets and explicit teaching can expand the knowledge base needed for later comprehension.'),
      q('How does text structure support comprehension?', 'Students list facts from an informational passage but miss the causal relationship. What should instruction emphasize?', 'Teach them to identify and use the passage’s causal organization, signal language, and relationships when summarizing.', ['Count paragraphs without analyzing connections.', 'Memorize the first sentence of each section.', 'Replace the passage with isolated vocabulary cards.'], 'Recognizing narrative and informational structures helps readers organize propositions, identify relationships, make inferences, and produce coherent summaries.'),
      q('Which discussion practice deepens comprehension?', 'A class discussion consists mostly of recall questions answered by one student at a time. What should the specialist recommend?', 'Use text-dependent, open questions that require evidence, explanation, comparison, and sustained student-to-student reasoning.', ['Ask only yes-or-no questions.', 'Accept opinions without reference to the text.', 'Avoid discussion until every student reads at the same rate.'], 'Extended, evidence-centered discussion makes reasoning visible, develops language, and supports interpretation when participation structures provide equitable access.'),
    ],
  },
  {
    id: 'writing-disciplinary-digital-literacy', chapterId: 'read5302-ch-05', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Writing, Disciplinary Literacy, and Digital Texts', references: [ETS, ILA, ILA_MATRIX, IES_ADOLESCENT],
    questions: [
      q('How are reading and writing instruction related?', 'Why should a literacy plan integrate reading and composing rather than treat them as separate blocks?', 'Reading provides models and knowledge for writing, while writing deepens analysis of language, text structure, evidence, and meaning.', ['Writing practice automatically fixes every decoding need.', 'Reading and writing share no underlying knowledge.', 'Composition should begin only after reading is mastered.'], 'Reading and writing are reciprocal but not identical; effective instruction connects them while directly teaching the distinct transcription, language, comprehension, and composition skills learners need.'),
      q('What should writing assessment distinguish?', 'A student has strong ideas but writes little because spelling and handwriting are effortful. What should the specialist examine?', 'Transcription fluency and accuracy separately from planning, language, organization, revision, and purpose.', ['Treat total word count as the only writing construct.', 'Assume limited output means limited knowledge.', 'Score handwriting appearance as reading comprehension.'], 'Writing performance reflects interacting transcription and composition demands; separating components reveals whether instruction should address mechanics, language, strategy, access, or several areas.'),
      q('What is disciplinary literacy?', 'Why might reading a laboratory report require different supports from reading a historical argument?', 'Disciplines use characteristic purposes, evidence, vocabulary, representations, and reasoning that should be taught explicitly.', ['Every subject uses identical text conventions.', 'Content teachers should avoid literacy instruction.', 'Disciplinary literacy means simplifying all texts.'], 'Students need general literacy skills and instruction in how experts in a discipline build claims, read sources, interpret representations, and communicate knowledge.'),
      q('How should a specialist support digital-text reading?', 'Students click links rapidly but do not evaluate or integrate information. What instruction is needed?', 'Teach navigation, source evaluation, lateral verification, synthesis across modes, and monitoring of purpose and attention.', ['Assume digital familiarity equals critical literacy.', 'Ban all hyperlinks without teaching evaluation.', 'Judge credibility by visual design alone.'], 'Digital literacy includes comprehension plus navigation, authorship and evidence checks, multimodal integration, privacy awareness, and strategic control of distraction.'),
      q('Why use coherent text sets?', 'A grade team selects several texts around one science concept. What is the strongest rationale?', 'Connected texts can build vocabulary and knowledge while allowing comparison of genres, claims, evidence, and perspectives.', ['Every text must use the same difficulty and viewpoint.', 'A text set eliminates the need for explicit instruction.', 'Students should memorize facts without discussing sources.'], 'Purposefully sequenced text sets support cumulative knowledge and language while creating opportunities for synthesis and critical examination.'),
      q('How can sentence-level instruction support literacy?', 'Students understand ideas orally but struggle with complex written syntax. What should instruction include?', 'Explicit work with sentence meanings, clauses, connectives, expansion, combining, and deconstruction in reading and writing contexts.', ['Label parts of speech without connecting them to meaning.', 'Reduce every text to short simple sentences permanently.', 'Teach punctuation as an isolated copying task only.'], 'Syntax instruction is most useful when students examine how sentence structures express relationships and apply that knowledge while comprehending and composing.'),
      q('What makes genre instruction transferable?', 'Students can fill in one narrative organizer but cannot plan a new story. What should change?', 'Teach the purposes, flexible structures, language features, and decision making of the genre across varied models and writing tasks.', ['Require the same template for every genre.', 'Focus only on page length.', 'Avoid mentor texts because students may imitate them.'], 'Genre knowledge becomes transferable when learners compare examples, discuss author choices, plan for audience and purpose, compose, receive feedback, and revise.'),
      q('How should evidence be taught in source-based writing?', 'A student inserts quotations but does not connect them to a claim. What feedback is most useful?', 'Select relevant evidence, introduce and represent it accurately, explain how it supports the claim, and cite the source appropriately.', ['Add more quotations without analysis.', 'Use only the longest available quotation.', 'Replace the claim with a source summary.'], 'Evidence functions through relevance and reasoning; source-based writing requires accurate representation, attribution, integration, explanation, and attention to audience and purpose.'),
    ],
  },
  {
    id: 'instructional-design-differentiation-engagement', chapterId: 'read5302-ch-06', domainId: 'curriculum-instruction', domain: 'Curriculum and Instruction',
    label: 'Instructional Design, Differentiation, Intervention, and Engagement', references: [ETS, ILA_MATRIX, IES_FOUNDATIONS, IES_ADOLESCENT, WIDA],
    questions: [
      q('What characterizes explicit literacy instruction?', 'A teacher tells students to ?use a strategy? but never demonstrates it. What should the specialist recommend?', 'State the goal, model the thinking and procedure, guide responsive practice with feedback, and move toward independent application.', ['Give the answer before every attempt indefinitely.', 'Use discovery alone for students with persistent difficulty.', 'Remove cumulative review once a skill is introduced.'], 'Explicit instruction makes the target and decision process visible, provides many successful responses and feedback, and fades support according to performance.'),
      q('What makes grouping flexible?', 'A school places students in a low reading group for the entire year. What is a better practice?', 'Group for a specific, assessed purpose and change membership as skills, texts, and instructional needs change.', ['Group permanently by a single composite score.', 'Use only whole-class instruction regardless of need.', 'Change groups randomly every day without data.'], 'Flexible grouping is temporary and purpose driven; it preserves access to rich instruction while allowing targeted teaching and response-based regrouping.'),
      q('How should differentiation preserve rigor?', 'A student needs support reading a grade-level science text. Which adjustment is most appropriate?', 'Maintain the important content and thinking goal while adding explicit vocabulary, chunking, accessible formats, guided reading, and response supports.', ['Replace the task with unrelated easy worksheets.', 'Remove all complex ideas from the unit.', 'Grade the student on a different hidden goal.'], 'Differentiation changes access, scaffolding, intensity, materials, grouping, or response options while keeping the intended construct and meaningful learning visible.'),
      q('Which support is appropriate for multilingual learners?', 'An English learner has strong ideas and home-language literacy but needs support with English academic text. What should instruction do?', 'Build on linguistic knowledge, teach English language forms and vocabulary explicitly, provide comprehensible interaction, and coordinate content and language goals.', ['Prohibit use of the home language.', 'Wait for conversational fluency before literacy instruction.', 'Assume every English error is a disability.'], 'Responsive instruction treats multilingualism as an asset and provides explicit access to the language of disciplinary texts without lowering intellectual demand.'),
      q('How can an intervention be intensified responsibly?', 'Progress data show insufficient response despite adequate implementation. What should the team do?', 'Use diagnostic evidence to adjust dimensions such as explicitness, dosage, group size, practice, feedback, linguistic support, or skill focus and monitor the change.', ['Change several unknown elements without documentation.', 'Repeat the same plan indefinitely.', 'Attribute nonresponse to motivation without evidence.'], 'Data-based intensification begins with fidelity and diagnostic review, makes a reasoned adaptation, documents it, and evaluates whether the change improves growth.'),
      q('What supports literacy engagement?', 'A capable student avoids reading because assigned texts feel irrelevant and success is rare. What is the strongest response?', 'Combine achievable challenge, meaningful choice, culturally responsive texts, explicit success supports, authentic purposes, and feedback that builds agency.', ['Offer only prizes for page counts.', 'Lower every task below the student?s skill level.', 'Require public comparison with faster readers.'], 'Engagement grows through competence, relevance, identity, autonomy, belonging, and purpose; it complements rather than replaces high-quality skill and knowledge instruction.'),
      q('What makes a literacy-rich environment instructionally useful?', 'A classroom has many books and a word wall that students rarely use. What should the coach emphasize?', 'Ensure materials are accessible, diverse, connected to instruction, inviting for authentic reading and writing, and explicitly used by students.', ['Count decorations as evidence of literacy growth.', 'Display only teacher-created work.', 'Organize books by perceived student ability and restrict access.'], 'The environment matters when students actively use varied print, digital tools, language resources, and their own work for meaningful literacy purposes.'),
      q('How should accessibility be incorporated into literacy instruction?', 'A learner needs text-to-speech for content access while also receiving decoding intervention. What is the best plan?', 'Provide the access tool for the content goal and continue direct instruction and measurement of decoding in tasks designed to assess decoding.', ['Withhold access until decoding is proficient.', 'Use text-to-speech as proof that decoding is unnecessary.', 'Score supported listening as an unaided decoding measure.'], 'Access and remediation can occur together when the team defines each task?s construct, documents supports, and avoids confusing assisted performance with the skill being directly measured.'),
    ],
  },
  {
    id: 'assessment-purposes-measurement-fairness', chapterId: 'read5302-ch-07', domainId: 'assessment', domain: 'Assessment',
    label: 'Assessment Purposes, Measurement, Selection, and Fairness', references: [ETS, ILA_MATRIX, NCII_TOOLS, IDEA_EVAL, WIDA],
    questions: [
      q('How do screening and diagnostic assessment differ?', 'A student scores below a benchmark on a universal reading screener. What does that result justify?', 'It identifies elevated risk and need for timely follow-up; diagnostic evidence is needed to specify skills and instruction.', ['It establishes a disability by itself.', 'It dictates one commercial intervention.', 'It proves the student received inadequate instruction.'], 'Screening prioritizes efficient risk identification, whereas diagnostic assessment samples components and error patterns to guide hypotheses and teaching.'),
      q('What is the purpose of progress monitoring?', 'Why administer a brief comparable reading measure repeatedly during intervention?', 'To estimate change toward a defined goal and support decisions about continuing, adjusting, or intensifying instruction.', ['To rediagnose the student every week.', 'To replace instruction with testing.', 'To compare unrelated skills at each administration.'], 'Progress monitoring uses repeated technically adequate measures of the same broad outcome or defined skill to evaluate responsiveness over time.'),
      q('What does reliability mean in assessment?', 'A reading measure yields highly inconsistent scores under comparable conditions. Which quality is weak?', 'The consistency or precision of the scores for the intended use.', ['The cultural relevance of the book list only.', 'The instructional intensity of the intervention.', 'The face attractiveness of the report.'], 'Reliability concerns score consistency and measurement error; it is necessary but does not by itself establish that an interpretation is valid or fair.'),
      q('What does validity mean?', 'A test produces consistent scores but does not adequately measure the reading construct used for the decision. What is the problem?', 'Evidence does not support the intended interpretation and use of the scores.', ['The test is invalid only because it is reliable.', 'The student must retake it until the score rises.', 'Validity is a permanent property independent of purpose.'], 'Validity concerns evidence for a particular interpretation and use in a defined population and context, not a universal label attached to an instrument.'),
      q('Why do sensitivity and specificity matter in screening?', 'A district evaluates a screener?s ability to identify students at risk without referring too many students who are not at risk. What is being balanced?', 'Correct identification of students with risk and correct exclusion of students without the target risk.', ['Interrater reliability and handwriting speed.', 'Percentile rank and grade equivalent.', 'Treatment fidelity and social validity.'], 'Sensitivity and specificity describe classification accuracy; thresholds should reflect prevalence, consequences, resources, equity, and the follow-up pathway.'),
      q('How do norm-referenced and criterion-referenced interpretations differ?', 'A report compares a learner with a representative peer group and also lists mastered spelling patterns. What are the two interpretations?', 'Norm referencing compares performance with a group; criterion referencing compares performance with defined skills or standards.', ['Both comparisons are grade-equivalent scores.', 'Criterion referencing ranks students only.', 'Norm referencing proves which lesson to teach next.'], 'Norms describe relative standing, while criterion information describes performance on specified content; each can contribute different evidence to a decision.'),
      q('How should standard error influence score interpretation?', 'A reading score is reported as if it were perfectly exact. What should the specialist add?', 'A confidence interval or other explanation of measurement uncertainty and the limits of small score differences.', ['A guarantee that the true score equals the obtained score.', 'A grade-equivalent conversion for every audience.', 'A new cutoff selected after seeing the result.'], 'Observed scores contain measurement error; confidence intervals and converging evidence reduce false precision and overinterpretation of minor differences.'),
      q('What makes an assessment fair?', 'A decoding test requires vocabulary and cultural knowledge unrelated to the intended word-reading construct. What should be examined?', 'Whether construct-irrelevant language, experience, access, administration, or scoring creates systematic barriers to the intended interpretation.', ['Whether every learner receives the same score.', 'Whether the test is short.', 'Whether all accommodations are prohibited.'], 'Fairness requires equitable opportunity to demonstrate the target construct and examination of bias, accessibility, consequences, and subgroup evidence.'),
      q('How should an accommodation be evaluated?', 'A student uses an approved support during a reading assessment. What must the team determine?', 'Whether the support improves access without changing the construct, and how it affects score comparability and interpretation.', ['Whether it makes the score higher.', 'Whether every student uses the same support.', 'Whether the support can remain undocumented.'], 'An accommodation should address an access barrier while preserving the intended construct; changes that alter the construct require different interpretation.'),
      q('Why is administration fidelity important?', 'A teacher changes timing and prompts on a standardized measure but reports the standard score. What is wrong?', 'Departures can invalidate the standard comparison and must be documented with appropriately limited interpretation.', ['All informal changes improve validity.', 'Standard scores remain comparable after any change.', 'Only the student needs to know about the change.'], 'Standardized scores depend on specified administration and scoring; accessible changes must follow allowable procedures or be reported as nonstandard.'),
    ],
  },
  {
    id: 'diagnostic-error-analysis-case-integration', chapterId: 'read5302-ch-08', domainId: 'assessment', domain: 'Assessment',
    label: 'Diagnostic Literacy Assessment, Error Analysis, and Case Integration', references: [ETS, ILA_MATRIX, IDA_KPS, IES_FOUNDATIONS, IDEA_EVAL, WIDA],
    questions: [
      q('What does a phoneme-analysis error reveal?', 'A child can blend /m/ /a/ /p/ but cannot segment ?map.? What is the clearest next instructional target?', 'Explicit supported phoneme segmentation linked to the letters once the oral task is understood.', ['Advanced figurative language.', 'Silent-reading endurance.', 'Dictionary guide words.'], 'The contrast between blending and segmentation identifies a specific sound-analysis need that can be taught directly and connected to encoding and decoding.'),
      q('Why use unfamiliar or pseudoword decoding tasks?', 'A student reads memorized words well but struggles with novel letter strings. What does a controlled unfamiliar-word task help assess?', 'Application of phoneme?grapheme and word-analysis knowledge without relying only on stored word familiarity.', ['Background knowledge of the story.', 'Writing organization.', 'Listening comprehension only.'], 'Novel-word tasks can sample generative decoding, but interpretation still requires appropriate language, pattern legality, instruction, and comparison with real-word and spelling evidence.'),
      q('What can an informal reading inventory contribute?', 'A specialist collects oral reading, retelling, and question responses across graded passages. How should the information be used?', 'As descriptive task evidence about accuracy, fluency, and comprehension, integrated with more reliable measures and authentic performance.', ['As a single standardized diagnosis.', 'As proof of an exact independent grade level.', 'As a replacement for word-level analysis.'], 'Passage inventories reveal strategies and errors in context but their level labels and comprehension scores can be unstable; decisions need converging evidence.'),
      q('How should spelling errors be analyzed?', 'A learner spells ?jumped? as ?jumpt? and ?running? as ?runing.? What is most useful?', 'Examine phoneme representation, orthographic conventions, inflectional morphology, and doubling patterns rather than count errors only.', ['Treat both words as random visual failures.', 'Assess comprehension instead of spelling.', 'Correct the words without identifying patterns.'], 'Feature analysis shows what the learner represents and which phonological, orthographic, syllabic, or morphological patterns need explicit instruction.'),
      q('How should an oral-reading-fluency score be interpreted?', 'A student reads many words correctly per minute but ignores punctuation and cannot explain the passage. What conclusion is warranted?', 'Rate is one indicator; accuracy, prosody, text conditions, language, and comprehension show that fluent meaningful reading is not yet established.', ['The student is fully fluent because rate is high.', 'The passage was understood because few words were missed.', 'Prosody is unrelated to syntax or meaning.'], 'A fluency decision integrates rate with accuracy, phrasing, expression, difficulty, and understanding rather than using a speed cutoff in isolation.'),
      q('What should a comprehension assessment sample?', 'A learner answers literal questions but struggles to integrate ideas across an informational text. What additional evidence is needed?', 'Inference, text structure, vocabulary, knowledge, monitoring, summarizing, and explanation using appropriately accessible texts.', ['Only faster oral reading.', 'Letter-name fluency.', 'Copying the passage.'], 'Comprehension is multidimensional and text dependent; aligned tasks help locate whether language, knowledge, strategic integration, print access, or task demands contribute.'),
      q('How can oral-language and decoding data clarify a case?', 'A student decodes accurately but has weak listening and reading comprehension. What instructional hypothesis is strongest?', 'Language comprehension, vocabulary, syntax, knowledge, and discourse need direct assessment and instruction while word reading is maintained.', ['More basic letter-name drills are necessarily primary.', 'Accurate decoding proves comprehension is normal.', 'The student should read harder text without support.'], 'Comparing listening, word recognition, fluency, and reading comprehension helps separate print-access and language-comprehension contributions.'),
      q('How should a multilingual student?s reading errors be evaluated?', 'An English learner shows errors consistent with features of the home language and limited English exposure. What should the specialist do?', 'Gather evidence across languages and contexts, instruction and opportunity, English development, cross-linguistic patterns, and response to teaching before inferring disability.', ['Diagnose disability from English errors alone.', 'Ignore persistent concerns because the student is multilingual.', 'Translate a normed test and retain its standard score automatically.'], 'Valid differential reasoning distinguishes language difference and developing English from disability using qualified multilingual evidence and converging patterns.'),
      q('What belongs in a comprehensive dyslexia evaluation?', 'A family asks whether one timed word list can confirm dyslexia. What is the best response?', 'Use developmental, instructional, language, functional, word-reading, decoding, spelling, fluency, phonological, and relevant exclusionary evidence under current criteria.', ['One reversal checklist is sufficient.', 'An intelligence?achievement discrepancy is always required.', 'Reading comprehension alone determines the diagnosis.'], 'No single measure establishes dyslexia; comprehensive evaluation documents a persistent pattern, impact, context, instruction, strengths, co-occurring factors, and applicable rules.'),
      q('What should a writing sample analysis include?', 'A student?s essay receives one holistic score. What evidence would better guide instruction?', 'Transcription, sentence construction, vocabulary, organization, genre, evidence, cohesion, revision, and the conditions and supports used.', ['Pen color and page margins only.', 'Reading rate only.', 'The number of paragraphs without content analysis.'], 'Analytic and process evidence separates spelling and handwriting demands from language and composition and identifies teachable patterns.'),
      q('How should a reading specialist synthesize a case?', 'Assessment sources disagree across one-to-one testing, classwork, and intervention. What is the best next step?', 'Compare constructs, tasks, reliability, access, context, fidelity, timing, and error patterns; state uncertainty and select evidence that can resolve the instructional decision.', ['Average every score regardless of construct.', 'Choose the lowest result automatically.', 'Ignore classroom performance because it is informal.'], 'Case integration explains convergence and conflict, links findings to instruction and function, and avoids false certainty or a list of disconnected scores.'),
    ],
  },
  {
    id: 'progress-monitoring-data-mtss', chapterId: 'read5302-ch-09', domainId: 'assessment', domain: 'Assessment',
    label: 'Progress Monitoring, Instructional Decisions, and MTSS Data', references: [ETS, ILA_MATRIX, NCII_PM, NCII_TOOLS, IDEA_EVAL],
    questions: [
      q('What makes progress-monitoring scores comparable over time?', 'A team changes passage difficulty and scoring rules every week. Why is the trend hard to interpret?', 'Measures should sample the same outcome with equivalent forms, consistent administration and scoring, and documented conditions.', ['Every probe should assess a different construct.', 'The highest weekly score should replace the trend.', 'Comparability matters only for norm-referenced tests.'], 'Growth interpretation depends on technical adequacy and comparable measurement; uncontrolled changes can create score differences unrelated to learning.'),
      q('How should a baseline be established?', 'One unusually low reading probe is used as the starting point for an intervention goal. What is better?', 'Use multiple valid observations or the measure?s recommended baseline procedure to reduce the influence of an atypical score.', ['Select the lowest score to show maximum growth.', 'Use a score from an unrelated skill.', 'Wait until intervention ends to define the baseline.'], 'A representative baseline anchors level and growth decisions; multiple observations and standardized procedures reduce random error and reactivity.'),
      q('What makes a progress goal defensible?', 'A team chooses an ambitious end point without considering current performance or measure norms. What should it do?', 'Set a time-bound goal using the baseline, meaningful outcome expectations, measure guidance, available evidence, and individualized team judgment.', ['Use the same numerical goal for every grade.', 'Choose a goal after seeing the final data.', 'Base the goal only on student preference.'], 'Goals should be ambitious and attainable enough to guide action, with their rationale, timeline, measure, and decision rules explicit.'),
      q('How should level and slope be interpreted together?', 'A student?s recent scores are below goal but increasing faster than before. What should the team examine?', 'Current performance level, rate and stability of growth, remaining time, goal relevance, fidelity, and diagnostic evidence before deciding.', ['Ignore the trend because the last score is below goal.', 'Declare success from one increase.', 'Change the outcome measure immediately.'], 'Level describes current performance and slope describes change; a sound decision uses the full series and preestablished rules rather than one point.'),
      q('Why check intervention fidelity before interpreting nonresponse?', 'A student shows little growth, but many intervention lessons were missed. What is the first team question?', 'Determine whether the planned content, dosage, grouping, and instructional procedures were delivered adequately and accessibly.', ['Assume the student cannot learn the skill.', 'Intensify an unknown program without review.', 'Exclude attendance from the data discussion.'], 'Response data cannot be attributed confidently to an intervention that was not implemented as planned; fidelity review precedes causal claims and guides next steps.'),
      q('What is the purpose of a phase-change line on a graph?', 'A specialist changes intervention dosage after a data review. How should the graph reflect this?', 'Mark when the documented instructional change began so trends before and after the adaptation can be interpreted.', ['Erase all earlier data.', 'Move the goal line to match the latest score.', 'Connect only the highest points.'], 'Phase-change documentation links decisions with implementation and helps teams evaluate whether a purposeful adaptation is followed by improved performance.'),
      q('How should a team respond to insufficient progress with adequate fidelity?', 'A learner?s trend remains below the goal despite a well-implemented intervention. What follows?', 'Review diagnostic and error data, form a reasoned hypothesis, intensify or adapt the plan, document the change, and continue frequent monitoring.', ['Continue indefinitely without change.', 'Switch to an unrelated intervention randomly.', 'End support because the data are low.'], 'Data-based individualization is an iterative cycle of validated intervention, progress data, diagnostic analysis, purposeful adaptation, and evaluation.'),
      q('How can schoolwide data be used responsibly?', 'A grade-level dashboard shows lower growth for one student group. What should leaders do?', 'Investigate opportunity, curriculum, instruction, access, measure fairness, implementation, and student evidence with the affected community before acting.', ['Rank teachers publicly from one metric.', 'Assume the group has lower ability.', 'Hide subgroup patterns to avoid concern.'], 'Aggregated data can reveal inequities and system needs, but valid improvement requires contextual analysis, disaggregation, stakeholder voice, and multiple evidence sources.'),
      q('How can students participate in progress monitoring?', 'A specialist wants progress data to support self-efficacy rather than label students. What should happen?', 'Explain the goal and graph accessibly, celebrate strategy-linked growth, invite reflection, and choose a next action without public comparison.', ['Display ranked scores for the class.', 'Withhold all data from the student.', 'Promise that effort always produces the same slope.'], 'Student involvement is strongest when data are understandable, private, connected to controllable strategies, and used for collaborative goal setting.'),
      q('How should progress data be communicated to families?', 'A graph is sent home with acronyms and no explanation. What should the specialist add?', 'Describe the measured skill, baseline, goal, intervention, trend, uncertainty, instructional decision, and ways the family can ask questions or contribute context.', ['Report only the percentile.', 'Guarantee a future outcome.', 'Share other students? identifiable data for comparison.'], 'Accessible communication translates data into the instructional question and next step while protecting privacy and inviting meaningful family partnership.'),
    ],
  },
  {
    id: 'diverse-learners-family-equity-access', chapterId: 'read5302-ch-10', domainId: 'professional-leadership', domain: 'Professional Leadership and Specialized Roles',
    label: 'Diverse Learners, Family Partnership, Equity, and Access', references: [ETS, ILA, ILA_MATRIX, WIDA, IDEA_EVAL, FERPA],
    questions: [
      q('What is an asset-based approach to multilingual literacy?', 'A team describes a student?s home-language knowledge only as interference. What should the specialist add?', 'Identify linguistic, cultural, literacy, and knowledge resources that can support English development while explicitly teaching new forms.', ['Ignore English instructional needs.', 'Require English-only thinking.', 'Assume transfer is identical across all languages.'], 'Asset-based practice recognizes transferable knowledge and identity while examining language-specific differences, opportunity, explicit instruction, and individual performance.'),
      q('How can cross-linguistic analysis support instruction?', 'A bilingual student applies a home-language spelling pattern in English. What is the best response?', 'Determine whether the pattern reflects predictable transfer, teach the relevant English contrast explicitly, and monitor growth across languages when possible.', ['Count it as proof of disability.', 'Ignore it because all transfer disappears automatically.', 'Discourage use of both languages.'], 'Cross-linguistic analysis helps distinguish developing language from persistent difficulty and turns contrastive patterns into explicit instructional opportunities.'),
      q('How should teams distinguish language difference from disability?', 'A multilingual learner struggles in English reading after limited access to instruction. What evidence is needed?', 'Quality and duration of instruction, language development, performance across languages and contexts, opportunity, valid measures, and response to targeted teaching.', ['An English-only cutoff score.', 'Family accent or immigration history.', 'A translated test with unchanged norms.'], 'Differential decisions require converging evidence that difficulty is not explained primarily by language development, culture, instruction, mobility, or access.'),
      q('What makes family literacy engagement reciprocal?', 'A school tells families to copy classroom routines but does not ask about home practices. What should change?', 'Learn family goals, languages, knowledge, texts, routines, and access; co-design feasible supports and communicate in preferred accessible ways.', ['Require one standardized home activity.', 'Judge engagement by school-event attendance only.', 'Use children as interpreters for confidential meetings.'], 'Reciprocal partnership values family expertise and shared decisions rather than treating families as passive implementers of school-selected practices.'),
      q('How should text selection support equity?', 'A curriculum includes only one cultural perspective and uses diverse texts only during celebrations. What should leaders do?', 'Build sustained access to accurate, varied authors, identities, genres, languages, complexity, and perspectives while examining representation and stereotypes.', ['Lower text complexity whenever culture is unfamiliar.', 'Select texts only by cover images.', 'Avoid discussing contested perspectives.'], 'Equitable text systems combine representation, authenticity, quality, access, challenge, and critical examination throughout the curriculum.'),
      q('How should a specialist support an advanced reader?', 'A high-achieving reader finishes quickly but receives only more of the same work. What is a better response?', 'Use evidence to provide deeper complexity, disciplinary inquiry, rich writing, authentic audience, choice, and attention to any uneven skill needs.', ['Assign additional repetitive worksheets.', 'Assume advanced reading eliminates all support needs.', 'Move the student ahead by text level alone.'], 'Advanced learners benefit from depth, complexity, knowledge, creativity, and responsive pacing, with assessment of strengths and any coexisting needs.'),
      q('What is the role of assistive technology in literacy access?', 'A student uses speech-to-text for a content writing task. How should the team interpret the product?', 'Evaluate the intended content and composition construct with the support while assessing transcription separately when that skill is the target.', ['Score speech-to-text as handwriting fluency.', 'Withhold the tool from all graded work.', 'Assume the tool creates the ideas.'], 'Assistive technology can reduce an access barrier; valid use requires clarity about the construct, instruction in tool use, documentation, and separate measurement when needed.'),
    ],
  },
  {
    id: 'coaching-professional-learning-collaboration', chapterId: 'read5302-ch-11', domainId: 'professional-leadership', domain: 'Professional Leadership and Specialized Roles',
    label: 'Coaching, Professional Learning, Collaboration, and Conflict Resolution', references: [ETS, ILA, ILA_MATRIX, IES_FOUNDATIONS, IES_ADOLESCENT],
    questions: [
      q('What should be clarified before a coaching cycle begins?', 'A teacher is unsure whether a reading specialist?s observation is evaluative. What is the best first step?', 'Clarify role, purpose, confidentiality limits, goals, data use, decision authority, and how feedback will be shared.', ['Begin recording the lesson secretly.', 'Promise absolute confidentiality regardless of policy.', 'Let administrators and teachers assume different purposes.'], 'Role clarity and informed agreements build trust and prevent coaching evidence from being used in ways participants did not understand.'),
      q('What makes coaching job embedded?', 'A workshop introduces an instructional routine, but teachers need classroom support. What should follow?', 'Use collaborative goal setting, co-planning, modeling or co-teaching, observation, feedback, rehearsal, and student evidence in the actual context.', ['Send a generic article only.', 'Wait until annual evaluation.', 'Require implementation without materials or practice.'], 'Job-embedded professional learning connects evidence and explanation with supported enactment, reflection, feedback, and iterative refinement.'),
      q('When is modeling most effective in coaching?', 'A specialist demonstrates a phonics lesson while the teacher watches. What should accompany the model?', 'A shared focus, explanation of key decisions, observable look-fors, debriefing, teacher rehearsal, and follow-up evidence.', ['An unannounced performance with no debrief.', 'A script the teacher must copy regardless of students.', 'Feedback limited to whether the lesson was entertaining.'], 'Modeling supports transfer when the instructional reasoning is visible and the teacher can analyze, practice, adapt, and receive feedback.'),
      q('How should professional learning be evaluated?', 'Participants report liking a literacy workshop. What additional evidence is needed?', 'Changes in educator knowledge and practice, implementation conditions, student opportunity and outcomes, and unintended effects over time.', ['Satisfaction ratings are sufficient.', 'One student score proves causation.', 'Attendance guarantees implementation.'], 'Professional learning evaluation moves beyond reaction to learning, enactment, system support, and relevant student evidence without overclaiming causality.'),
      q('What is a constructive response to instructional disagreement?', 'Two teachers disagree sharply about how to teach word recognition. How should the specialist facilitate?', 'Define the shared student goal, surface assumptions and evidence, examine data and standards, agree on a testable plan, and set a review point.', ['Choose the loudest position.', 'Avoid the issue until conflict disappears.', 'Frame disagreement as personal resistance.'], 'Collaborative conflict resolution preserves relationships while making the instructional question, evidence, decision process, and follow-up explicit.'),
      q('How do adult-learning principles inform literacy coaching?', 'A specialist plans identical lectures for experienced teachers with different needs. What would improve the design?', 'Use relevant problems, prior expertise, choice, active practice, feedback, collaboration, and immediate application while maintaining clear outcomes.', ['Assume adults learn best through passive compliance.', 'Avoid acknowledging existing expertise.', 'Separate all learning from classroom problems.'], 'Effective adult learning is purposeful, respectful, active, context connected, and supported over time rather than a one-time information delivery.'),
      q('What makes a literacy data meeting productive?', 'A team spends the meeting reading scores aloud without making decisions. What should the facilitator change?', 'Use a focused question, prepared disaggregated evidence, agreed norms, analysis of instruction and access, a documented action, owner, measure, and review date.', ['Add more unrelated dashboards.', 'Use the meeting to rank teachers.', 'End without recording the decision.'], 'A disciplined inquiry cycle turns data into a specific, testable instructional or system action and protects against deficit explanations and meeting drift.'),
    ],
  },
  {
    id: 'program-leadership-mtss-ethics-privacy', chapterId: 'read5302-ch-12', domainId: 'professional-leadership', domain: 'Professional Leadership and Specialized Roles',
    label: 'Program Leadership, MTSS, Ethics, Privacy, and Advocacy', references: [ETS, ILA, ILA_MATRIX, NCII_PM, NCII_TOOLS, FERPA, IDEA_EVAL],
    questions: [
      q('What is the reading specialist?s role in MTSS leadership?', 'A school treats tiers as fixed student labels. What should the specialist emphasize?', 'Coordinate evidence-based core instruction, screening, timely support, progress monitoring, collaborative decisions, intensification, and movement based on need; MTSS must not delay or deny an evaluation when one is warranted.', ['Assign students permanently to tiers.', 'Use intervention as a substitute for special-education evaluation.', 'Make the specialist solely responsible for all struggling readers.'], 'MTSS is a prevention and support framework involving system quality and increasingly intensive response, not a static placement or reason to delay required evaluation.'),
      q('How should a literacy program be evaluated?', 'School leaders want to judge a new curriculum from one year-end average. What broader evidence is needed?', 'Implementation and opportunity, component outcomes and growth, subgroup access, educator learning, materials, intervention coherence, stakeholder experience, and unintended effects.', ['The vendor?s testimonials only.', 'One grade?s highest score.', 'Teacher compliance without student evidence.'], 'Program evaluation examines whether the design was enacted, for whom it worked, under what conditions, and what should be sustained, adapted, or discontinued.'),
      q('How should leaders select literacy materials or programs?', 'A vendor claims its intervention is ?research based.? What should the team ask?', 'Examine independent evidence quality and fit, content and instructional design, assessment alignment, population, implementation demands, accessibility, cost, and monitoring plan.', ['Select the most colorful materials.', 'Treat a citation list as proof of effectiveness.', 'Ignore local capacity and learner profiles.'], 'Responsible adoption combines evidence appraisal with curricular quality, contextual fit, equity, feasibility, professional learning, and an explicit evaluation plan.'),
      q('How should identifiable literacy data be shared?', 'A coach wants to email a student?s detailed reading profile to a broad staff list. What should happen?', 'Verify legitimate educational interest, applicable FERPA and local policy, consent or authority, secure method, and the minimum information needed.', ['Share because all employees work for the district.', 'Remove the name but leave uniquely identifying details.', 'Post the profile in the staff room.'], 'Education records require role-based, purpose-limited, secure handling under current law and policy; professional curiosity is not the same as legitimate educational interest.'),
      q('How should a specialist handle a financial conflict?', 'A reading specialist receives compensation for recommending one commercial program. What is required?', 'Disclose the conflict, follow ethics and procurement rules, present objective evidence and alternatives, and recuse when impartial judgment cannot be preserved.', ['Hide the relationship if the program is popular.', 'Use student data in marketing without authorization.', 'Guarantee results to justify the purchase.'], 'Transparency and independent evidence protect students, schools, and professional trust when personal interests could influence recommendations.'),
      q('What makes literacy advocacy evidence based?', 'A leader wants a policy change after hearing one compelling story. What should the specialist contribute?', 'Combine student and family experience with disaggregated data, research quality, legal and equity analysis, resource implications, implementation planning, and measurable review.', ['Dismiss lived experience because it is not experimental.', 'Promise the policy will help every student.', 'Present only evidence supporting the preferred position.'], 'Responsible advocacy integrates multiple forms of evidence, identifies uncertainty and tradeoffs, centers affected communities, and includes a way to evaluate consequences.'),
    ],
  },
];

